### Error Handling Best Practices:
```javascript
// Custom error classes
class NetworkError extends Error {
  constructor(message, statusCode) {
    super(message);
    this.name = 'NetworkError';
    this.statusCode = statusCode;
  }
}

async function safeFetch(url) {
  const response = await fetch(url);

  if (response.status === 404) throw new NetworkError('Not found', 404);
  if (response.status === 401) throw new NetworkError('Unauthorized', 401);
  if (!response.ok) throw new NetworkError(`HTTP Error`, response.status);

  return response.json();
}

// Usage
try {
  const data = await safeFetch('/api/data');
} catch (error) {
  if (error instanceof NetworkError) {
    console.error(`${error.statusCode}: ${error.message}`);
  } else {
    console.error('Unknown error:', error);
  }
}
```

