    function renderTodos() {
      updateStats();
      const filtered = getFilteredTodos();

      if (filtered.length === 0) {
        todoList.innerHTML = `
          <div class="empty-state">
            <span>${currentFilter === 'completed' ? '🎉' : '📝'}</span>
            ${currentFilter === 'completed' 
              ? 'Abhi tak kuch complete nahi!'
              : 'Koi task nahi! Naya add karo 👆'}
          </div>
        `;
        return;
      }

      todoList.innerHTML = filtered.map(todo => `
        <li class="todo-item ${todo.completed ? 'completed' : ''}" data-id="${todo.id}">
          <input 
            type="checkbox" 
            class="todo-checkbox" 
            ${todo.completed ? 'checked' : ''}
            onchange="toggleTodo(${todo.id})"
          >
          <span class="todo-text" title="Added: ${todo.createdAt}">${todo.text}</span>
          <div class="todo-actions">
            <button class="edit-btn" onclick="editTodo(${todo.id})">✏️</button>
            <button class="delete-btn" onclick="deleteTodo(${todo.id})">🗑️</button>
          </div>
        </li>
      `).join('');
    }

    // Filter Buttons
    filterBtns.forEach(btn => {
      btn.addEventListener('click', () => {
        currentFilter = btn.dataset.filter;
        filterBtns.forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        renderTodos();
      });
    });

    // Add Button
    addBtn.addEventListener('click', addTodo);

    // Enter Key
    input.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') addTodo();
    });

    // Clear Completed
    clearBtn.addEventListener('click', () => {
      const completedCount = todos.filter(t => t.completed).length;
      if (completedCount === 0) {
        alert('Koi completed todo nahi hai!');
        return;
      }
      if (confirm(`${completedCount} completed todos delete karein?`)) {
        todos = todos.filter(t => !t.completed);
        saveTodos();
        renderTodos();
      }
    });

    // Initial render
    renderTodos();
    console.log('✅ Aperonix Todo App loaded! Created by Mohammad Khan');
  </script>
</body>
</html>
